args.sparql:
SELECT ?award ?awardLabel WHERE {
  ?category rdfs:label "Best actress"@en .
  ?award wdt:P2458 ?category .
  ?award rdfs:label ?awardLabel .
  FILTER(LANG(?awardLabel) = 'en') .
} LIMIT 1

SELECT ?award ?awardLabel WHERE {
  ?award wdt:P31 wd:Q6063734;
         rdfs:label ?awardLabel.
  FILTER(LANG(?awardLabel) = 'en') .
  FILTER(CONTAINS(LCASE(?awardLabel), 'best actress')) .
} LIMIT 10

